  ('police-94737317-moex-00006', 'police-94737317', 'police-94737317-moex-114-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '有關憲法居住自由之保障，下列敘述何者錯誤？', '["憲法上的居住自由強調的是住宅的不可侵犯性", "都市更新事項僅涉及人民財產權保障，與居住自由無涉", "居住自由的保護法益，係保障生活空間的隱私權", "人民的居住自由不能衍生出擁有住宅權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "9fb671cdee0b", "answer_pdf_sha1": "a4de01131286", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "602", "s": "0210", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
