  ('police-94737317-moex-00010', 'police-94737317', 'police-94737317-moex-114-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '人民對於確定終局裁判所適用之法令，經司法院解釋宣告違憲，釋憲聲請人據以提起再審之訴者，其 再審最長期間5年之計算，應否扣除聲請案繫屬司法院大法官審理之期間？', '["不應扣除", "應予扣除", "由檢察官定執行刑", "視情形而定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "9fb671cdee0b", "answer_pdf_sha1": "a4de01131286", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "602", "s": "0210", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00011', 'police-94737317', 'police-94737317-moex-114-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '有關憲法第10條保障遷徙自由之敘述，下列何者正確？', '["外國人合法進入我國國境後，不受遷徙自由保障", "強制合法入境之大陸地區人民出境，與遷徙自由保障無涉", "對在國內無戶籍之我國國民進入國境，予以限制，與憲法保障遷徙自由之意旨不符", "國家為確保稅收，依法限制欠稅者出境，與憲法保障遷徙自由之意旨並無牴觸"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "9fb671cdee0b", "answer_pdf_sha1": "a4de01131286", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "602", "s": "0210", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00012', 'police-94737317', 'police-94737317-moex-114-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '有關立法院立法委員選舉，各政黨依得票率選出之當選名單中婦女之席次數，下列敘述何者正確？', '["不得低於2分之1", "應過半數", "應與男性當選人之席位相同", "不得低於3分之2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "9fb671cdee0b", "answer_pdf_sha1": "a4de01131286", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "602", "s": "0210", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('police-94737317-moex-00013', 'police-94737317', 'police-94737317-moex-114-14ea90a7', 'sub-police-94737317-01', NULL, 'single_choice', '按人民受教育之權利，依其憲法規範基礎之不同，可區分為「受國民教育之權利」及「受國民教育以 外教育之權利」。有關前述二種權利，下列敘述何者正確？', '["此二種權利皆兼有義務之性質", "只有「受國民教育之權利」兼有義務之性質", "只有受「國民教育以外教育之權利」兼有義務之性質", "此二種權利皆僅有權利之性質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "9fb671cdee0b", "answer_pdf_sha1": "a4de01131286", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "602", "s": "0210", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中華民國憲法與消防警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "消防警察人員"}'::jsonb, NULL),
